require "base.ui.window.GUISumRechargeReward"

local function getChildWindow(window, name, type)
    local child = window:getChildWindow(name, type)
    if not child then
        error("SumRechargeLayout must have" .. name .. " child window.")
    end
    return child
end

local UISumRechargeLayout = class("UISumRechargeLayout", IGUILayout)

function UISumRechargeLayout:onLoad()
    self.currentId = 0
    self.currentGCube = 0
    self.rewardWidth = 80

    local name = string.gsub(self.__name, ".json", "-")
    self.tvTitle = getChildWindow(self, name .. "Title", GUIType.StaticText)
    self.tvHint = getChildWindow(self, name .. "Hint", GUIType.StaticText)
    self.ivMainImage = getChildWindow(self, name .. "Main-Image", GUIType.StaticImage)
    self.awMainActor = getChildWindow(self, name .. "Main-Actor", GUIType.ActorWindow)
    self.ivSubImage = getChildWindow(self, name .. "Sub-Image", GUIType.StaticImage)
    self.tvRechargeValue = getChildWindow(self, name .. "Recharge-Value", GUIType.StaticText)
    self.pbRechargeProgress = getChildWindow(self, name .. "Recharge-Progress", GUIType.ProgressBar)
    self.btnRecharge = getChildWindow(self, name .. "Recharge", GUIType.Button)

    local llRewards = getChildWindow(self, name .. "Rewards", GUIType.Layout)
    self.gvRewards = IGUIGridView.new("SumRechargeLayout-Reward-List", llRewards)
    self.gvRewards:setConfig(10, 10, 3)

    local btnClose = getChildWindow(self, name .. "Close", GUIType.Button)
    local btnSmallClose = getChildWindow(self, name .. "Small-Close", GUIType.Button)
    btnClose:registerEvent(GUIEvent.ButtonClick, function()
        self:hide()
    end)
    btnSmallClose:registerEvent(GUIEvent.ButtonClick, function()
        self:hide()
    end)

    self.btnRecharge:registerEvent(GUIEvent.ButtonClick, function()
        local config = SumRechargeConfig:getSumRecharge(self.currentId)
        if not config then
            return
        end
        if self.currentGCube >= config.GCube then
            local player = Game:getPlayer()
            local inv = player:getInventory()
            local emptyCount = inv:getEmptyStackCount()
            if emptyCount < #config.Rewards then
                if not InventoryNotEnoughEvent:invoke() then
                    return
                end
            end
            PacketSender:sendLuaCommonData("SumRechargeReceive")
            self:hide()
        else
            ClientHelper.onRecharge(1)
        end
    end)

    self.btnRecharge:SetText(Lang:getString("sum.recharge.goto.recharge"))
end

function UISumRechargeLayout:onShow(id)
    if not id then
        return
    end
    if self.currentId == id then
        return
    end
    self.currentId = id
    local config = SumRechargeConfig:getSumRecharge(self.currentId)
    if not config then
        return
    end
    self.tvTitle:SetText(Lang:getString(config.TitleLang))
    self.tvHint:SetText(Lang:getString(config.HintLang))
    self.ivMainImage:SetImage(config.LayoutMainImage)
    if string.find(config.LayoutMainImage, ".actor") ~= nil then
        self.ivMainImage:SetVisible(false)
        self.awMainActor:SetVisible(true)
        self.awMainActor:SetActor1(config.LayoutMainImage, "idle", 0)
    else
        self.ivMainImage:SetVisible(true)
        self.awMainActor:SetVisible(false)
        self.ivMainImage:SetImage(config.LayoutMainImage)
    end
    self.ivSubImage:SetImage(config.LayoutSubImage)
    self.gvRewards:clearItems()

    LuaTimer:schedule(function()
        if not SumRechargeCreateItemsEvent:invoke() then
            return
        end
        local contentWidth = self.gvRewards:getWidth()
        local count = math.min(math.floor(contentWidth / self.rewardWidth), #config.Rewards)
        local space = (contentWidth - self.rewardWidth * count) / (count - 1)
        self.gvRewards:setConfig(space, space, count)
        local lines = math.ceil(#config.Rewards / count)
        local itemHeight = self.gvRewards:getHeight() / lines
        local rewards = config.Rewards
        for _, reward in pairs(rewards) do
            local item = GUISumRechargeReward.new(config.RewardUIName)
            item:setRewardItem(reward)
            item:setWidth({ 0, self.rewardWidth })
            item:setHeight({ 0, itemHeight })
            self.gvRewards:addItem(item)
        end
        self.gvRewards.root:SetClipChild(false)
    end, 100)
    self:updateGCubeValue(self.currentGCube)
end

function UISumRechargeLayout:updateGCubeValue(gcube)
    self.currentGCube = gcube
    local config = SumRechargeConfig:getSumRecharge(self.currentId)
    if not config then
        return
    end
    self.tvRechargeValue:SetText(string.format("%s/%s", tostring(self.currentGCube), tostring(config.GCube)))
    self.pbRechargeProgress:SetProgress(self.currentGCube / config.GCube)
    if self.currentGCube >= config.GCube then
        self.btnRecharge:SetText(Lang:getString("sum.recharge.goto.receive"))
        self.btnRecharge:SetNormalImage(config.ReceiveImage)
        self.btnRecharge:SetPushedImage(config.ReceiveImage)
    else
        self.btnRecharge:SetText(Lang:getString("sum.recharge.goto.recharge"))
        self.btnRecharge:SetNormalImage(config.RechargeImage)
        self.btnRecharge:SetPushedImage(config.RechargeImage)
    end
end

function UISumRechargeLayout:setRewardWidth(width)
    self.rewardWidth = width or 80
end

function UISumRechargeLayout:registerEvents()
    self:registerDataCallBack("ShowSumRecharge", function(data)
        local id = data:getParam("Id")
        local remind = data:getBoolParam("Remind")
        local config = SumRechargeConfig:getSumRecharge(id)
        if config then
            if self.__name ~= config.LayoutUIName then
                self:reload(config.LayoutUIName)
            end
            self:onShow(id)
            if remind then
                LuaTimer:schedule(function()
                    GUIManager:addShowQueue(GUISumRechargeLayout)
                end, 1000)
            end
        else
            self:hide()
        end
    end, DataBuilderProcessor)
    self:registerDataCallBack("SumRechargeGCube", function(data)
        self:updateGCubeValue(tonumber(data))
    end)
end

function UISumRechargeLayout:reload(name)
    GUIManager:removeLayout(self)
    GUIManager:destroyGUIWindow(self.root)
    for key, value in pairs(self) do
        if type(value) == "userdata" then
            self[key] = nil
        end
    end
    self.__name = name
    self:load()
end

function UISumRechargeLayout:onHide()
    self.taskFinished = true
    LogUtil.log("UISumRechargeLayout:onHide taskFinished")
end

return UISumRechargeLayout